// src/App.js
import { BrowserRouter as Router, Routes, Route, useLocation } from "react-router-dom";
import { useState, useEffect } from "react";

import Navbar from "./components/Navbar";
import Footer from "./components/Footer";

import Home from "./pages/Home";
import Login from "./pages/Login";
import Register from "./pages/Register";
import Cart from "./pages/Cart";
import Category from "./pages/Category";
import Shop from "./components/Shop";
import SellerDashboard from "./pages/SellerDashboard";
import ProductDetails from "./pages/ProductDetails"; // 👈 NEW PAGE


// slick CSS
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import "./styles/Slick.css";
import "./index.css";

function AppWrapper() {
  const location = useLocation(); // Get current path
  const [successMessage, setSuccessMessage] = useState("");

  // Auto-hide success message
  useEffect(() => {
    if (successMessage) {
      const timer = setTimeout(() => setSuccessMessage(""), 2500);
      return () => clearTimeout(timer);
    }
  }, [successMessage]);

  // Hide footer on seller dashboard
  const hideFooter = location.pathname === "/seller";

  return (
    <>
      {successMessage && <div className="success-message">{successMessage}</div>}


      <Navbar />

      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/shop" element={<Shop />} />
        <Route path="/product/:id" element={<ProductDetails />} /> {/* 👈 NEW ROUTE */}
        <Route path="/login" element={<Login setSuccessMessage={setSuccessMessage} />} />
        <Route path="/register" element={<Register setSuccessMessage={setSuccessMessage} />} />
        <Route path="/cart" element={<Cart />} />
        <Route path="/category" element={<Category />} />
        <Route path="/seller" element={<SellerDashboard />} />
      
      </Routes>

      {!hideFooter && <Footer />}
    </>
  );
}

function App() {
  return (
    <Router>
      <AppWrapper />
    </Router>
  );
}

export default App;
